const keywords = [
  // SOLARSPEICHER – HOCH
  { keyword: 'Sungrow SBR', category: 'solarspeicher' },
  { keyword: 'BYD HVS Speicher', category: 'solarspeicher' },
  { keyword: 'BYD Battery Box', category: 'solarspeicher' },
  { keyword: 'Anker Solix Speicher', category: 'solarspeicher' },
  { keyword: 'Pylontech Speicher', category: 'solarspeicher' },
  { keyword: 'SENEC Speicher', category: 'solarspeicher' },
  { keyword: 'E3DC Hauskraftwerk', category: 'solarspeicher' },
  { keyword: 'Victron Speicher', category: 'solarspeicher' },
  // SOLARZAUN – HOCH
  { keyword: 'Solarzaun', category: 'solarzaun' },
  { keyword: 'PV Zaun bifazial', category: 'solarzaun' },
  { keyword: 'bifaziale Solarmodule Zaun', category: 'solarzaun' },
  // SOLARANLAGE + SPEICHER – MITTEL
  { keyword: 'Photovoltaik Komplettanlage Speicher', category: 'solaranlage' },
  { keyword: 'PV Anlage mit Speicher', category: 'solaranlage' },
  // WECHSELRICHTER – MITTEL
  { keyword: 'Sungrow Hybrid Wechselrichter', category: 'wechselrichter' },
  { keyword: 'Fronius Hybrid Wechselrichter', category: 'wechselrichter' },
  // BALKONKRAFTWERK + SPEICHER – MITTEL
  { keyword: 'Balkonkraftwerk Speicher', category: 'balkonkraftwerk' },
  { keyword: 'Anker Solix Balkonkraftwerk', category: 'balkonkraftwerk' },
];

return keywords.map(k => ({ json: k }));

const keyword = $('Keywords laden').item.json.keyword;
const category = $('Keywords laden').item.json.category;

const raw = $input.first().json;
let apifyItems = [];

if (Array.isArray(raw)) {
  apifyItems = raw;
} else if (raw && typeof raw === 'object') {
  const arrayVal = Object.values(raw).find(v => Array.isArray(v));
  if (arrayVal) apifyItems = arrayVal;
}

const seen = new Set();
const listings = [];

for (const r of apifyItems) {
  if (!r || typeof r !== 'object') continue;

  const url = String(r.url || r.link || r.href || r.listingUrl || '').trim();

  // adId aus URL extrahieren (7-12 stellige Zahl im Pfad, vor Bindestrichen)
  let adId = null;
  const urlPath = url.split('?')[0].split('#')[0];
  for (const seg of urlPath.split('/')) {
    const part = seg.split('-')[0];
    if (part.length >= 7 && part.length <= 12) {
      let isNum = true;
      for (let i = 0; i < part.length; i++) {
        const c = part.charCodeAt(i);
        if (c < 48 || c > 57) { isNum = false; break; }
      }
      if (isNum) { adId = part; break; }
    }
  }

  const title = String(r.title || r.name || r.headline || '').trim();
  if (!adId || !title) continue;
  if (seen.has(adId)) continue;
  seen.add(adId);

  const price = r.price || r.priceText || r.priceRaw || r.priceFormatted || null;

  let image = null;
  if (Array.isArray(r.images) && r.images.length > 0) {
    image = String(r.images[0]);
  } else {
    image = r.image || r.imageUrl || r.thumbnail || r.photo || null;
  }

  const plzRaw = r.zip || r.zipCode || r.postalCode || r.plz || null;

  listings.push({
    adId,
    title,
    price: price != null ? String(price).trim() : null,
    description: r.description || r.text || r.body || null,
    location: r.location || r.address || r.city || r.area || null,
    plz: plzRaw != null ? String(plzRaw).trim() : null,
    date: r.date || r.createdAt || r.listedAt || r.publishedAt || null,
    url: url || null,
    image: image ? String(image) : null,
    shipping: r.shipping || r.shippingCost || null,
  });
}

return [{
  json: {
    source: 'kleinanzeigen',
    keyword,
    category,
    listingCount: listings.length,
    listings,
  }
}];
